/** F3 (WP-F): Build a plan symbol for a column — solid base footprint, optional dashed top footprint for sloped columns. */
function columnPlanThree(col: Extract<Element, { kind: 'column' }>): THREE.Group {
  const grp = new THREE.Group();
  grp.userData.bimPickId = col.id;

  const bM = (col.bMm ?? 300) / 1000;
  const hM = (col.hMm ?? 300) / 1000;
  const cx = ux(col.positionMm.xMm);
  const cz = uz(col.positionMm.yMm);
  const Y = PLAN_Y + 0.006;

  const color = readToken('--plan-wall', '#1c1917');

  // Solid base footprint rectangle
  const hbx = bM / 2;
  const hbz = hM / 2;
  const corners: THREE.Vector3[] = [
    new THREE.Vector3(cx - hbx, Y, cz - hbz),
    new THREE.Vector3(cx + hbx, Y, cz - hbz),
    new THREE.Vector3(cx + hbx, Y, cz + hbz),
    new THREE.Vector3(cx - hbx, Y, cz + hbz),
    new THREE.Vector3(cx - hbx, Y, cz - hbz),
  ];
  grp.add(
    new THREE.Line(
      new THREE.BufferGeometry().setFromPoints(corners),
      new THREE.LineBasicMaterial({ color }),
    ),
  );

  // Diagonal cross
  grp.add(
    new THREE.Line(
      new THREE.BufferGeometry().setFromPoints([
        new THREE.Vector3(cx - hbx, Y, cz - hbz),
        new THREE.Vector3(cx + hbx, Y, cz + hbz),
      ]),
      new THREE.LineBasicMaterial({ color }),
    ),
  );
  grp.add(
    new THREE.Line(
      new THREE.BufferGeometry().setFromPoints([
        new THREE.Vector3(cx + hbx, Y, cz - hbz),
        new THREE.Vector3(cx - hbx, Y, cz + hbz),
      ]),
      new THREE.LineBasicMaterial({ color }),
    ),
  );

  // F3: dashed top footprint + centre-to-centre diagonal for sloped columns
  const txMm = col.topOffsetXMm ?? 0;
  const tyMm = col.topOffsetYMm ?? 0;
  if (txMm !== 0 || tyMm !== 0) {
    const tx = txMm / 1000;
    const ty = tyMm / 1000;
    const tcx = cx + tx;
    const tcz = cz + ty;
    const topCorners: THREE.Vector3[] = [
      new THREE.Vector3(tcx - hbx, Y, tcz - hbz),
      new THREE.Vector3(tcx + hbx, Y, tcz - hbz),
      new THREE.Vector3(tcx + hbx, Y, tcz + hbz),
      new THREE.Vector3(tcx - hbx, Y, tcz + hbz),
      new THREE.Vector3(tcx - hbx, Y, tcz - hbz),
    ];
    const dashedMat = new THREE.LineDashedMaterial({ color, dashSize: 0.05, gapSize: 0.03 });
    const dashedLine = new THREE.Line(new THREE.BufferGeometry().setFromPoints(topCorners), dashedMat);
    dashedLine.computeLineDistances();
    grp.add(dashedLine);

    // Line connecting base centre to top centre
    const diagMat = new THREE.LineDashedMaterial({ color, dashSize: 0.04, gapSize: 0.02 });
    const diagLine = new THREE.Line(
      new THREE.BufferGeometry().setFromPoints([
        new THREE.Vector3(cx, Y, cz),
        new THREE.Vector3(tcx, Y, tcz),
      ]),
      diagMat,
    );
    diagLine.computeLineDistances();
    grp.add(diagLine);
  }

  return grp;
}

